import React from 'react';
import './Stock.css'

function DisplayStockData({ stockData }) {
  if (!stockData) {
    return <p>Enter a symbol to fetch data</p>;
  }
  // const arrow = stockData.pChange > 0 ? '🔺' : '🔻';
  const isStockUp = stockData.change > 0;

  return (
    <div className='info'>
      <p>{stockData.symbol} {isStockUp ? <span style={{color: "yellow"}}></span> : <span style={{color: "red"}}></span>} </p>
      <p>{stockData.price} {isStockUp ? <span style={{color: "yellow"}}></span> : <span style={{color: "red"}}></span>} </p>
      <p>{stockData.change} {isStockUp ? <span style={{color: "yellow"}}></span> : <span style={{color: "red"}}></span>}</p>
      <p style={{color: isStockUp ? "yellow" : "red"}}>{stockData.pChange} {isStockUp ? <span>&#9650;</span> : <span>&#9660;</span>}</p>
    </div>
  );
}

export default DisplayStockData;
